mapper.update:
UPDATE MISSION
SET is_active = 'N'
WHERE mission_id = #{missionId}
  AND parent_id = #{parentId}
  AND is_active = 'Y'

mapper.delete:
DELETE FROM NOTIFICATION n
WHERE n.mission_id = #{missionId}
  AND EXISTS (
      SELECT 1
      FROM MISSION m
      WHERE m.mission_id = n.mission_id
        AND m.parent_id = #{parentId}
        AND NOT EXISTS (
            SELECT 1
            FROM MISSION_SUBMISSION ms
            WHERE ms.mission_id = m.mission_id
        )
  )

DELETE FROM MISSION m
WHERE m.mission_id = #{missionId}
  AND m.parent_id = #{parentId}
  AND m.mission_title != 'default_media_mission'
  AND NOT EXISTS (
      SELECT 1
      FROM MISSION_SUBMISSION ms
      WHERE ms.mission_id = m.mission_id
  )

mapper.select:
SELECT COUNT(*)
FROM MISSION_SUBMISSION
WHERE child_id = #{childId}
  AND mission_id = #{missionId}
  AND mission_date = TRUNC(SYSDATE)
  AND status IN ('pending', 'approved')

SELECT COUNT(*)
FROM MISSION_SUBMISSION ms
JOIN CHILD c ON c.child_id = ms.child_id
WHERE ms.media_url = #{mediaUrl}
  AND c.parent_id = #{parentId}
  AND ms.media_deleted_at IS NULL

SELECT COUNT(*)
FROM MISSION_SUBMISSION
WHERE media_url = #{mediaUrl}
  AND child_id = #{childId}
  AND media_deleted_at IS NULL

SELECT box_grade, box_name, min_exp, max_exp, pet_drop_rate
FROM REWARD_BOX
WHERE box_grade = #{boxGrade}

mapper.update:
UPDATE MISSION_SUBMISSION
SET reward_given = 'Y'
WHERE submission_id = #{submissionId}
  AND child_id = #{childId}
  AND status = 'approved'
  AND reward_given = 'N'

UPDATE NOTIFICATION
SET is_read = 'Y',
    read_at = SYSTIMESTAMP
WHERE notification_id = #{notificationId}
  AND parent_id = #{parentId}
  AND is_read = 'N'

UPDATE NOTIFICATION
SET is_read = 'Y',
    read_at = SYSTIMESTAMP
WHERE notification_id = #{notificationId}
  AND child_id = #{childId}
  AND is_read = 'N'
